import React from 'react';
import { useNavigate } from 'react-router-dom';

const Dashboard = ({ schedule, setSchedule }) => {
    const navigate = useNavigate();

    // Calculate Progress
    const completedCount = schedule ? schedule.filter(t => t.status === 'completed').length : 0;
    const progress = schedule ? (completedCount / schedule.length) * 100 : 0;

    const handleGenerate = () => {
        // Example generator if schedule is null
        const newSchedule = [
            { day: 1, topic: 'React Hooks', status: 'pending' },
            { day: 2, topic: 'Node.js', status: 'pending' },
        ];
        setSchedule(newSchedule);
    };

    return (
        <div style={{ padding: '40px' }}>
            <h1>Your Study Roadmap</h1>
            
            {!schedule ? (
                <button onClick={handleGenerate}>Generate Schedule</button>
            ) : (
                <>
                    {/* Progress Bar */}
                    <div style={{ width: '100%', height: '15px', background: '#eee', borderRadius: '10px', marginBottom: '10px' }}>
                        <div style={{ width: `${progress}%`, background: '#4CAF50', height: '100%', borderRadius: '10px', transition: '0.5s' }} />
                    </div>
                    <p>{Math.round(progress)}% Completed</p>

                    {/* Day Grid */}
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px', marginTop: '20px' }}>
                        {schedule.map((item) => (
                            <div 
                                key={item.day}
                                onClick={() => item.status !== 'completed' && navigate(`/study-session/${item.day}`)}
                                style={{ 
                                    padding: '20px', 
                                    border: '1px solid #ddd', 
                                    borderRadius: '8px', 
                                    background: item.status === 'completed' ? '#d4edda' : '#fff',
                                    cursor: item.status === 'completed' ? 'default' : 'pointer'
                                }}
                            >
                                <strong>Day {item.day}</strong>
                                <p>{item.topic}</p>
                                <span style={{ color: item.status === 'completed' ? 'green' : 'orange' }}>
                                    {item.status === 'completed' ? '✅ Completed' : '⏳ Start Session'}
                                </span>
                            </div>
                        ))}
                    </div>
                </>
            )}
        </div>
    );
};

export default Dashboard;
